INSERT INTO bot_settings (key, value, updated_at) VALUES
  ('payment_intro_en', replace('💰 Add Balance\n\n💵 Current Balance: {{balance}}\n\nAvailable payment options:\n\n💳 Binance Pay (USDT)\n🟥 bKash: {{bkash}} (Send Money)\n🟧 Nagad: {{nagad}} (Send Money)\n🟪 Rocket: temporarily unavailable\n🟨 Upay: {{upay}} (Send Money)\n\nMobile wallets are personal accounts.\n\n👇 Select the payment method:', '\n', char(10)), CURRENT_TIMESTAMP),
  ('payment_intro_bn', replace('💰 ব্যালেন্স যোগ করুন\n\n💵 বর্তমান ব্যালেন্স: {{balance}}\n\nপেমেন্ট অপশন:\n\n💳 Binance Pay (USDT)\n🟥 bKash: {{bkash}} (Send Money)\n🟧 Nagad: {{nagad}} (Send Money)\n🟪 Rocket: সাময়িকভাবে বন্ধ\n🟨 Upay: {{upay}} (Send Money)\n\nমোবাইল ওয়ালেটগুলো Personal Account।\n\n👇 পেমেন্ট পদ্ধতি বাছুন:', '\n', char(10)), CURRENT_TIMESTAMP),
  ('payment_provider_en', replace('💳 {{provider}}\n\nSend Money to: {{account}}\nAccount type: Personal\n\nSend the payment amount in BDT.\nExample: 500', '\n', char(10)), CURRENT_TIMESTAMP),
  ('payment_provider_bn', replace('💳 {{provider}}\n\nSend Money করুন: {{account}}\nAccount type: Personal\n\nBDT-তে পেমেন্ট এমাউন্ট লিখুন।\nউদাহরণ: 500', '\n', char(10)), CURRENT_TIMESTAMP),
  ('binance_payment_provider_en', replace('💳 Add Balance via Binance Pay\n\n📱 Binance Pay ID:\n{{pay_id}}\n\n⚠️ Instructions:\n1️⃣ Open Binance App\n2️⃣ Go to Pay → Send\n3️⃣ Enter the Pay ID above\n4️⃣ Enter the USDT amount\n5️⃣ Complete payment\n6️⃣ Copy the Order ID from Binance\n7️⃣ Send the Order ID here (just the ID)\n\n📝 Now reply with your Binance Order ID:', '\n', char(10)), CURRENT_TIMESTAMP),
  ('binance_payment_provider_bn', replace('💳 Binance Pay দিয়ে ব্যালেন্স যোগ করুন\n\n📱 Binance Pay ID:\n{{pay_id}}\n\n⚠️ নির্দেশনা:\n1️⃣ Binance App খুলুন\n2️⃣ Pay → Send এ যান\n3️⃣ উপরের Pay ID দিন\n4️⃣ USDT amount দিন\n5️⃣ পেমেন্ট সম্পন্ন করুন\n6️⃣ Binance থেকে Order ID কপি করুন\n7️⃣ শুধু Order ID এখানে পাঠান\n\n📝 এখন আপনার Binance Order ID পাঠান:', '\n', char(10)), CURRENT_TIMESTAMP)
